"""
mkt-christ layer — Acts all 28 chapters
Output: data/commentary/mkt-christ/acts.json

Acts presents Christ as the risen Lord who continues to act through the Spirit
and the church. The Christological trajectory in Acts is consistently resurrection-
centered: Jesus is the fulfillment of every OT expectation precisely because
he died and rose. The five directness levels apply to each pericope.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(layer, book):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(layer, book, data):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

CHRIST = {
  "1": {
    "9": "<p>A direct revelation: the ascension is not the departure of Christ but the enthronement of the crucified-and-risen Lord. When the cloud receives Jesus (<em>nephelē hypelaben auton</em>), Luke invokes the Danielic cloud-of-divine-presence (Dan 7:13-14) and the Sinai theophany cloud. The Christological point: Christ is not leaving the world but entering the place of cosmic authority at the Father's right hand, from which he will send the Spirit (2:33) and to which believers' prayers are addressed. The disciples' upward gaze is redirected by the angels — not to the sky but to the world they are sent to fill with witnesses.</p>",

    "11": "<p>A direct revelation: 'This Jesus, who was taken up from you into heaven, will come in the same way as you saw him go into heaven.' The parousia-promise anchors Christian hope in the personal return of the same embodied, risen Lord who ascended — not a spiritual presence-return (already given at Pentecost) but the eschatological appearing of the glorified Christ. The continuity of identity ('this Jesus') is christologically critical: the one who comes is the one who died, who rose, who ascended — resurrection-continuity spans from the tomb to the parousia.</p>"
  },
  "2": {
    "36": "<p>A direct revelation: 'God has made him both Lord and Christ, this Jesus whom you crucified.' This is the climax of Peter's Pentecost sermon and one of the densest Christological sentences in the NT. <em>Kurios</em> (Lord) carries the full weight of the LXX divine name (YHWH); <em>Christos</em> (Christ/Messiah) the royal-covenantal designation. The resurrection-exaltation is the moment of enthronement — not that Jesus became Lord only then (his pre-existence is assumed throughout Acts' theology), but that the cosmic lordship is now publicly declared and the messianic mission fulfilled. The audience ('whom you crucified') makes the declaration forensically stunning: the crucified one is the enthroned Lord.</p>"
  },
  "3": {
    "15": "<p>A direct revelation: 'You killed the Author of life, whom God raised from the dead.' <em>Archēgon tēs zōēs</em> (pioneer/author of life) is one of Acts' most original Christological titles. The paradox is maximal: the one who is the source and pioneer of life was put to death. The resurrection is not merely resuscitation but the vindication of Christ's identity — if God raised him, God endorses his claims. Peter's speech invites repentance not as moral self-improvement but as a re-orientation toward the one they killed, now established as the sole mediator of life.</p>"
  },
  "4": {
    "12": "<p>A direct revelation: 'There is salvation in no one else, for there is no other name under heaven given among people by which we must be saved.' The exclusivity claim (<em>ouk estin en allō oudeni hē sōtēria</em>) is made before the supreme Jewish court that had condemned Jesus. Peter's Christocentrism is absolute and public: not 'Jesus is one path among many' but the singular name by which salvation comes. The <em>dei</em> (must) is divine necessity — salvation through this name is not a human option but a divine appointment. The Christological uniqueness of Acts 4:12 is the evangelical confession that animates the entire mission of the book.</p>"
  },
  "7": {
    "56": "<p>A direct revelation: 'Behold, I see the heavens opened, and the Son of Man standing at the right hand of God.' Stephen's vision at the moment of martyrdom is the only post-resurrection appearance of the risen Christ to someone other than Paul in Acts (the Damascus road, 9:4-5). The 'Son of Man' title — Jesus's own self-designation during his ministry (Luke 9:22; 22:69) — is used here by Stephen, the only NT speaker outside the Gospels to use this title of Jesus. The standing Christ (see mkt-original note on <em>hestōta</em>) is the risen Lord actively receiving his first martyr. Christology is here embedded in pneumatology: the Spirit-filled Stephen sees the Christological reality that sustains martyrdom.</p>"
  },
  "8": {
    "35": "<p>A fulfillment: Philip 'beginning from this Scripture proclaimed good news about Jesus' — the Ethiopian's question about Isa 53:7-8 is answered by identifying the silent suffering lamb as Jesus. This is the apostolic hermeneutic in miniature: the Suffering Servant is not Israel in general or Isaiah himself but the specific individual who died silently and was raised ('his life is taken away from the earth' → resurrection reversal). The Christological reading of Isa 53 as a resurrection narrative (the servant suffers, is cut off, but the Lord 'prolongs his days', Isa 53:10 MT) is already present in Jesus's own self-understanding (Luke 22:37) and becomes the template for apostolic preaching throughout Acts.</p>"
  },
  "9": {
    "5": "<p>A direct revelation: 'I am Jesus, whom you are persecuting.' The Damascus road self-disclosure is the risen Christ identifying himself with the community he is building: to persecute the church is to persecute Jesus. The identification is ontological, not merely moral — Christ's body is so united to the community of believers that assault on one is assault on the other. This is the experiential foundation of Paul's later 'body of Christ' ecclesiology (1 Cor 12:12-27; Eph 4:15-16): the risen Lord is not spatially removed from his people but present in them, suffering with them, and encountered through them.</p>"
  },
  "10": {
    "43": "<p>A direct revelation: 'To him all the prophets bear witness that everyone who believes in him receives forgiveness of sins through his name.' Peter's summary of the OT witness to Christ is comprehensive ('all the prophets') and universalizing ('everyone who believes'). The Cornelius episode's Christological climax is precisely this: the same Christ who is the subject of all prophetic testimony is the one through whom Gentiles receive forgiveness. The Spirit's falling on the Gentiles mid-sermon (v. 44) is God's own validation of this Christological universalism — the risen Christ's lordship over all flesh (Joel 2:28) enacted in real time.</p>"
  },
  "13": {
    "30": "<p>A direct revelation: 'But God raised him from the dead; and for many days he appeared to those who had come up with him from Galilee to Jerusalem, who are now his witnesses to the people.' Paul at Pisidian Antioch places the resurrection as the pivotal event that all of Israel's history was pointing toward — the promises to the patriarchs (v. 32), the Davidic covenant (v. 34), and the resurrection prophecies of the Psalms (Ps 2:7; Ps 16:10; Isa 55:3) all converge on this fact. The witnesses from Galilee are the guarantors of historical continuity: the risen one is the same Jesus who walked those roads. Christology is not mythology but testified history.</p>",

    "47": "<p>A fulfillment: Paul cites Isa 49:6 ('I have made you a light for the Gentiles, that you may bring salvation to the ends of the earth') as the scriptural mandate for the Gentile mission. The Servant's commission is now Christ's commission extended through Paul and Barnabas. This is typological fulfillment: the Servant who could not be restricted to Israel's restoration alone (Isa 49:6a) prefigures Christ whose mission overflows every ethnic and geographic boundary. Paul's application of the Servant commission to himself and Barnabas (first person plural) shows that missionaries participate in Christ's Servant identity — they are his instruments in the fulfillment of Isa 49.</p>"
  },
  "15": {
    "14": "<p>A fulfillment: James cites Amos 9:11-12 — 'I will return and rebuild the tent of David that has fallen' — as fulfilled in Christ's resurrection and the formation of the Gentile church. The 'tent of David' in Amos is the Davidic dynasty; its 'rebuilding' in LXX Amos is translated in terms broad enough to include all the Gentiles who bear God's name. James's pesher reading: Christ's resurrection is the rebuilding of the Davidic tent; the Gentile mission is the fulfillment of Amos's promise that all nations will seek the Lord. The Jerusalem Council's doctrinal resolution is grounded not in pragmatics but in Christological exegesis: the Gentile mission is what Scripture said the Messiah would accomplish.</p>"
  },
  "17": {
    "31": "<p>A direct revelation: 'He has fixed a day on which he will judge the world in righteousness by a man whom he has appointed, and of this he has given assurance to all by raising him from the dead.' Paul's Areopagus speech concludes with the risen Christ as the eschatological judge appointed by God. The Christological claim before a philosophical audience that had no framework for bodily resurrection (<em>anastasis</em>, v. 32, provoked mockery) is the irreducible skandalon of the gospel: not a timeless philosophical principle but a specific man, raised from the dead, appointed to judge all. The resurrection is both validation of Jesus's identity and guarantee of universal accountability before him.</p>"
  },
  "20": {
    "28": "<p>A direct revelation: 'Pay careful attention to yourselves and to all the flock, in which the Holy Spirit has made you overseers, to care for the church of God, which he obtained with his own blood.' The theological density of this charge to the Ephesian elders is unparalleled in Acts: (1) the Spirit appoints church leadership; (2) the church belongs to God himself; (3) God purchased this church through blood that is 'his own'. Whether <em>tou haimatos tou idiou</em> is rendered 'his own blood' (ascribing blood to God the Father, implying the Son's blood is God's own) or 'the blood of his own [Son]', the Christological purchase is irreversible and costly beyond measure. The cross is the price God paid for his own community.</p>"
  },
  "26": {
    "23": "<p>A direct revelation: Paul's testimony before Agrippa distills his entire gospel: 'that the Christ must suffer and that, by being the first to rise from the dead, he would proclaim light both to our people and to the Gentiles.' Three elements define this Christological summary: (1) necessity (<em>pathētos</em>, <em>dei</em>) — the Christ was destined to suffer, fulfilling a divine plan woven into Scripture; (2) priority (<em>prōtos ex anastaseōs nekrōn</em>) — Christ's resurrection is the first of the general resurrection, making him the firstfruits (1 Cor 15:20) of the new creation; (3) universality — the resurrection-proclamation of light reaches both Israel and the nations. The entire Pauline mission is Christologically compressed into one sentence.</p>"
  },
  "28": {
    "31": "<p>A direct revelation: Acts closes with Paul 'proclaiming the kingdom of God and teaching about the Lord Jesus Christ with all boldness and without hindrance.' The final phrase — <em>akōlytōs</em>, unhindered — is the book's last word and its thesis. The risen Lord whose story opened Acts (1:1-11) has accomplished through broken, imprisoned, shipwrecked witnesses what he promised: testimony from Jerusalem to the heart of the empire. The kingdom of God and the Lord Jesus Christ are the twin proclamations that summarize the entire Lukan-Acts narrative: God's reign arrives in the person and work of Jesus, vindicated by resurrection, extended by the Spirit, and declared to all nations without hindrance.</p>"
  }
}

FILL_CH7 = {
  "7": {
    "1": "<p>The high priest's question — 'Are these things so?' — opens the judicial hearing that becomes Stephen's great Christological sermon. The format (defendant given opportunity to speak before the Sanhedrin) mirrors Jesus's own trial (Luke 22:66-71). Stephen's response will not be a defense of himself but an indictment of the court — the pattern of the prophets who spoke truth before power, the pattern Christ himself modeled (Luke 23:2-3, 8-9).</p>",
    "2": "<p>'The God of glory appeared to our father Abraham' (<em>ho theos tēs doxēs ōphthē tō patri hēmōn Abraam</em>) — Stephen's opening is a Christological thesis in miniature. The God who reveals himself as 'glory' (the Shekinah tradition) appeared to Abraham outside the land and before the covenant institutions. This establishes the pattern Stephen will trace: divine initiative precedes and exceeds every institutional form. The 'God of glory' will appear again at the end of the speech — in the face of the crucified Jesus, whom Stephen sees enthroned (v. 55-56).</p>",
    "3": "<p>God's call to Abraham — 'Go out from your land and from your kindred' (Gen 12:1) — is the paradigmatic form of the divine call that requires leaving the familiar to follow God into the unknown. The Christological echo: Jesus himself calls disciples to leave family and possessions (Luke 14:26-27); the cross is the ultimate 'going out from' the security of this age. Abraham's obedient departure without knowing where he was going (Heb 11:8) is the type of faith the crucified-and-risen Christ calls his followers to.</p>",
    "4": "<p>Abraham's journey from Ur to Haran to Canaan — a life of pilgrimage without permanent settlement — prefigures the Christological community that 'has no lasting city but seeks the city to come' (Heb 13:14). The Christological reading of the patriarchal narrative: the people of God are constitutively a people in movement, oriented toward promise rather than possession. Jesus himself 'had nowhere to lay his head' (Luke 9:58) — the pattern of homeless pilgrimage is the Christological mode of existence.</p>",
    "5": "<p>'Yet he gave him no inheritance in it, not even a foot's length, but promised to give it to him as a possession and to his offspring after him, though he had no child' — the promise without present possession is the structure of Abrahamic faith. The Christological fulfillment: the inheritance promised to Abraham's offspring is ultimately secured through Christ, the singular seed (Gal 3:16). Abraham believed a resurrection-like promise — a dead womb brought to life — pointing toward the resurrection of the one in whom all nations are blessed.</p>",
    "6": "<p>'His offspring would be sojourners in a land belonging to others, enslaved and afflicted for four hundred years' — the Egypt prophecy (Gen 15:13) establishes the pattern: God's people suffer in foreign servitude before the great deliverance. The Christological typology: Christ's own suffering and death is the supreme instance of the righteous one's affliction — and his resurrection is the supreme Exodus. The Exodus story that Stephen is tracing is the type whose antitype is the cross and resurrection.</p>",
    "7": "<p>'But I will judge the nation that they serve, and after that they shall come out and worship me in this place' — the Exodus promise includes both divine judgment on oppressors and the gathering of God's people for worship. The Christological fulfillment: the judgment on the powers that crucified Christ is executed in the resurrection (which vindicates Christ and condemns the accusers); the gathering for worship is the apostolic community of Acts. 'This place' is ultimately not a geographic location but the presence of the risen Lord.</p>",
    "8": "<p>'And he gave him the covenant of circumcision' — the sign-covenant given to Abraham and transmitted through Isaac, Jacob, and the twelve patriarchs establishes the covenant people's identity. The Christological frame: Paul will argue (Rom 4; Gal 3) that circumcision was a sign of the righteousness of faith that Abraham had before circumcision — the covenant of promise precedes and exceeds the covenant of signs. Christ fulfills the promise, not merely the sign.</p>",
    "9": "<p>'And the patriarchs, jealous of Joseph, sold him into Egypt; but God was with him' (<em>ho de theos ēn met' autou</em>) — the Joseph narrative introduces the defining pattern of Stephen's Christological typology: the rejected deliverer whom God vindicates. Joseph is sold by his brothers (type of Christ betrayed by one of his own), suffers in Egypt (type of Christ's humiliation), but God's presence persists through the rejection and through it accomplishes the salvation of those who rejected him.</p>",
    "10": "<p>'And rescued him out of all his afflictions and gave him favor and wisdom before Pharaoh, king of Egypt, who made him ruler over Egypt and over all his household' — God's vindication of Joseph through elevation to Pharaoh's right hand is the Joseph-type's closest correspondence to the resurrection-exaltation of Christ. The rejected one becomes the sovereign; the one whom brothers wanted dead becomes the one through whom they live. Christ seated at the right hand of God (2:33-34) completes what Joseph's story prefigured.</p>",
    "11": "<p>The famine that drove Jacob's sons to Egypt — forcing the very men who sold Joseph to come to him for grain — enacts the reversal pattern of Christological typology. The rejected one becomes the only source of life; those who rejected him must come to him or die. The gospel's logic is structurally identical: the one rejected and crucified is now the only source of life for those who crucified him (3:14-15 — 'you killed the Author of life, whom God raised').</p>",
    "12": "<p>'Jacob heard that there was grain in Egypt, and he sent our fathers out on their first visit' — the first visit without recognition parallels the pattern of rejection-then-recognition that runs through both the Joseph story and Luke's Gospel (the disciples on the Emmaus road who did not recognize the risen Christ until the breaking of bread, Luke 24:13-35). Divine provision is present before recognition dawns.</p>",
    "13": "<p>'On the second visit Joseph made himself known to his brothers' — the second-visit revelation (Gen 45:1-15) is the moment of recognition and reconciliation. The Christological echo: Christ's second appearing — the parousia — will be the universal moment of recognition, when 'every eye will see him, even those who pierced him' (Rev 1:7; cf. Zech 12:10). The Joseph narrative's two-visit structure prefigures the two-advent pattern of Christological revelation.</p>",
    "14": "<p>Joseph sent for Jacob and all his family — seventy-five souls (LXX count) — to come to Egypt. The gathering of the whole family around the vindicated Joseph corresponds to the gathering of Israel around the vindicated Christ. The Christological community is assembled by the exalted one who sends his Spirit to draw his people to himself (John 12:32 — 'when I am lifted up from the earth, I will draw all people to myself').</p>",
    "15": "<p>Jacob's death in Egypt and the burial promise — both Jacob and Joseph died there, though the promise of the land remained unfulfilled — maintains the tension of Christological promise-without-possession that Stephen is tracing. The patriarchs lived and died as sojourners whose hope reached beyond their lifetimes. The Christological community lives in the same structure: the promise is certain but its fullness awaits the parousia.</p>",
    "16": "<p>The burial of the patriarchs at Shechem (in the tomb Abraham bought from the sons of Hamor) — Stephen's account differs from the Genesis record (which places Jacob at Machpelah) and may reflect alternative traditions or deliberate summary. The theological point remains: the patriarchs were buried in the promised land as a down-payment on the inheritance. Their tombs are Christological pledges: God's promises outlast death, just as Christ's resurrection is God's pledge of the general resurrection (1 Cor 15:20-23).</p>",
    "17": "<p>'As the time of the promise drew near' (<em>kathōs de ēngizen ho chronos tēs epangelias</em>) — the language of approach and fulfillment. The Christological reading of Exodus: Israel's multiplication and oppression are not random historical events but the eschatological intensification before God acts decisively. The pattern — suffering preceding redemption, darkness before dawn — is the template for the Christological passion-before-resurrection structure. Every 'darkest before dawn' moment in Israel's history anticipates the supreme darkness of the cross before the dawn of resurrection.</p>",
    "18": "<p>'Until there arose over Egypt another king who did not know Joseph' — the erasure of Joseph from Pharaoh's memory enacts the perennial pattern: institutional power forgets its indebtedness to the one who saved it and turns against the next deliverer. The Christological echo: the chief priests who should have recognized the Messiah had forgotten the prophets' testimony to him, or suppressed it. Every generation's rejection of God's deliverer follows the same pattern of willful ignorance.</p>",
    "19": "<p>Pharaoh's genocidal program against Hebrew male infants — 'so that they might not be kept alive' (<em>tou mē zōogoneisthai</em>) — is the demonic attempt to eliminate the deliverer before he arrives. The Christological parallel: Herod's massacre of the Bethlehem infants (Matt 2:16-18) is the typological repetition — the powers that fear the true King attempt to eliminate him at birth. The pattern of satanic preemptive violence against God's deliverer runs from Pharaoh through Herod to the cross.</p>",
    "20": "<p>'At this time Moses was born; and he was beautiful in God's sight' (<em>asteios tō theō</em>, beautiful/acceptable to God) — the divine commendation of Moses at birth mirrors the Christological affirmation at Jesus's baptism ('You are my beloved Son; with you I am well pleased', Luke 3:22). Both the type and the antitype bear God's prior approval before their public ministry begins. Moses's three-month concealment by his parents (Heb 11:23 — by faith) parallels the protection of the infant Jesus in Egypt.</p>",
    "21": "<p>The abandonment and adoption of Moses — thrown into the Nile, drawn out by Pharaoh's daughter — enacts the pattern of apparent abandonment and unexpected rescue. The Christological echo of the cross: the cry of dereliction ('my God, my God, why have you forsaken me?', Luke 23:34 implied) is the deepest expression of apparent abandonment; the resurrection is the unexpected rescue by the Father. What looked like the end became the beginning of the greater life.</p>",
    "22": "<p>'Moses was instructed in all the wisdom of the Egyptians, and he was mighty in his words and deeds' — Moses's education in the highest learning of his age, combined with divine power, equipped him for his deliverer role. The Christological comparison: Jesus grew 'in wisdom and in stature and in favor with God and man' (Luke 2:52); his Nazareth teaching amazed those who heard him (Luke 4:22). Both Moses and Christ are the most fully formed human beings of their generation, equipped beyond their contemporaries for divine mission.</p>",
    "23": "<p>'When he was forty years old, it came into his heart to visit his brothers, the children of Israel' — Moses's spontaneous identification with his enslaved people, though raised in privilege, is the type of the incarnation. Christ 'though he was rich, yet for your sake he became poor' (2 Cor 8:9); 'he did not count equality with God a thing to be grasped, but emptied himself, taking the form of a servant' (Phil 2:6-7). Moses's voluntary identification with the afflicted foreshadows the incarnation's voluntary solidarity with the human condition.</p>",
    "24": "<p>Moses defended the oppressed Israelite and struck the Egyptian — the first messianic act, violent and unauthorized. The Christological contrast: Christ's defense of the oppressed was achieved not through violence against oppressors but through his own suffering. Moses's way became the type that Christ reversed: instead of the deliverer striking the oppressor, the deliverer absorbed the oppressor's violence to break its power. The contrast illuminates the newness of Christ's messianic method.</p>",
    "25": "<p>'He supposed that his brothers would understand that God was giving them salvation by his hand, but they did not understand' (<em>ou synekan</em>) — the failure to understand the deliverer in the moment of deliverance is Stephen's first indictment. The Christological application is unmistakable: Jesus's own people 'did not know the time of their visitation' (Luke 19:44). The pattern of missed recognition — the deliverer present but unrecognized — runs from Moses to Christ. Israel's history is a history of not understanding God's chosen saviors.</p>",
    "26": "<p>Moses's attempt to reconcile two quarreling Israelites — 'men, you are brothers; why are you wronging each other?' — is met with immediate hostility: 'who made you a ruler and a judge over us?' The Christological parallel: Jesus the peacemaker was consistently rejected by those whose peace he sought (Luke 19:41-42 — 'would that you, even you, had known the things that make for peace'). The deliverer who comes to reconcile is accused of power-seeking by those who resist reconciliation.</p>",
    "27": "<p>'Who made you a ruler and a judge over us?' — the question posed to Moses is the question posed to Jesus throughout his ministry: by what authority? (Luke 20:2). The resistance to divinely appointed authority is Stephen's core accusation against Israel's religious leaders: they have consistently asked God's messengers, 'who authorized you?' rather than recognizing the divine authorization in the messenger's works and words. The same question will be implicitly posed to Stephen himself — by the very court that poses it.</p>",
    "28": "<p>'Do you want to kill me as you killed the Egyptian yesterday?' — the threat against Moses by his own kinsman forces his flight. The Christological irony sharpens: Moses, who killed an Egyptian oppressor in defense of his people, is threatened with death by the people he came to save. Jesus, who raised the dead and healed the sick for his people, was threatened and finally killed by the people he came to save (John 1:11 — 'he came to his own, and his own people did not receive him').</p>",
    "29": "<p>Moses's flight to Midian and forty-year sojourn — exiled from the people he came to save — corresponds to the period of Israel's rejection. The Christological typology: between Moses's first and second coming to Israel (Exodus 2-3 — the first, rejected; Exodus 3-4 — the second, accepted), there is a gap of preparation and divine equipping. Between Christ's first coming (rejected) and second coming (accepted), there is the present age of witness. The exile of the deliverer is not defeat but preparation.</p>",
    "30": "<p>The angel in the burning bush — 'after forty years had passed, an angel appeared to him in the wilderness of Mount Sinai, in a flame of fire in a bush' — is the divine theophany that commissions Moses for his second visit. The Christological resonance: the flame of fire that appeared in the burning bush appears again at Pentecost (2:3 — 'tongues as of fire'). The same divine presence that equipped Moses for the first Exodus equips the church for the new Exodus. The theophany is Christologically continuous.</p>",
    "31": "<p>Moses's amazement at the burning bush — 'as he drew near to look, there came the voice of the Lord' — combines vision and audition in the encounter with the divine. The Christological pattern: divine initiative (the fire), human response (drawing near), divine address (the voice). The structure is repeated in every conversion in Acts: the divine initiative (the Spirit's work), the human response (turning), the personal address (the gospel). Moses's burning-bush experience is the paradigm of encounter with the living God through Christ.</p>",
    "32": "<p>'I am the God of your fathers, the God of Abraham and of Isaac and of Jacob.' The divine self-identification at the burning bush (Exod 3:6) is the basis for Jesus's resurrection argument in the Gospels (Luke 20:37-38 — 'Moses showed that the dead are raised… for he calls the Lord the God of Abraham and the God of Isaac and the God of Jacob. Now he is not God of the dead, but of the living'). The burning-bush theophany, rightly read, is a resurrection proof: the God of the patriarchs is still their God, which requires that they live.</p>",
    "33": "<p>'Take off the sandals from your feet, for the place where you are standing is holy ground' — the holy ground of the divine presence reveals a Christological principle: wherever God is present, the ordinary becomes sacred. The temple was 'holy ground' institutionally; but Christ declared that he would make his dwelling in any two or three gathered in his name (Matt 18:20), and that the Spirit-indwelt body is the temple (1 Cor 6:19). The holy ground moves from a fixed location to wherever Christ's Spirit is present.</p>",
    "34": "<p>'I have surely seen the affliction of my people who are in Egypt, and have heard their groaning, and I have come down to deliver them' (Exod 3:7-8) — the divine sight-hearing-coming-delivering sequence is the structure of the incarnation. The Christological reading of Exod 3: what God declares to Moses is literally enacted in Christ. God sees human affliction → sends his Son; hears human groaning → the incarnate Son weeps and intercedes; comes down → the Word becomes flesh; delivers → the cross and resurrection accomplish the ultimate Exodus. Moses's commission announces what Christ accomplishes.</p>",
    "35": "<p>'This Moses, whom they rejected, saying, 'Who made you a ruler and a judge?' — this man God sent as both ruler and deliverer by the hand of the angel who appeared to him in the bush.' Stephen's explicit typological statement: the rejected Moses is the one God vindicates and sends as deliverer. The Christological application is structural: this is exactly the pattern of Jesus. The double designation 'ruler and deliverer' (<em>archonta kai lytrōtēn</em>) corresponds to 'Lord and Christ' (2:36) — the rejected one receives from God the authority his rejectors denied him.</p>",
    "36": "<p>'This man led them out, performing wonders and signs in Egypt and at the Red Sea and in the wilderness for forty years' — Moses's miracle-signs are the pattern for apostolic signs throughout Acts (2:43; 4:30; 5:12; 6:8; 8:13). Every apostolic miracle is performed in Christ's name (3:6; 4:10) and derives from Christ's resurrection power. The Exodus signs are the type; the gospel's signs are the antitype. Christ is the greater Moses who performs the greater signs: raising the dead, healing at a word, casting out demons by his authority.</p>",
    "37": "<p>A fulfillment: 'This is the Moses who said to the Israelites, 'God will raise up for you a prophet like me from your brothers.'' (Deut 18:15) — the second time this text appears in Acts (first in 3:22 by Peter). Stephen cites it as Moses's own prophecy that transcends Moses: the deliverer Moses was would be succeeded by a greater deliverer. The Christological identification of Jesus as the Prophet-like-Moses is the hinge of Stephen's entire speech — the argument that what Moses announced, Jesus fulfills, making rejection of Jesus a rejection of Moses.</p>",
    "38": "<p>'This is the one who was in the congregation in the wilderness with the angel who spoke to him at Mount Sinai, and with our fathers. He received living oracles (<em>logia zōnta</em>) to give to us.' Moses received the Torah as 'living oracles'; Christ gives the Spirit, who is the fulfillment of the Torah's life-giving intention (Rom 8:4 — 'the righteous requirement of the law is fulfilled in us, who walk not according to the flesh but according to the Spirit'). The living oracles of Sinai become the living water of the Spirit that Christ pours out (John 7:38-39).</p>",
    "39": "<p>'Our fathers refused to obey him, but thrust him aside, and in their hearts turned to Egypt' — the wilderness generation's rejection of Moses is the definitive instance of the pattern Stephen traces. 'In their hearts they turned to Egypt' captures the perennial temptation: to return to the familiar bondage rather than follow the deliverer into the promised unknown. The Christological application: the Sanhedrin's rejection of Jesus is the contemporary instance of the same heart-Egypt. The form changes; the pattern is identical.</p>",
    "40": "<p>'Saying to Aaron, 'Make for us gods who will go before us. As for this Moses who led us out from the land of Egypt, we do not know what has happened to him'' — the golden calf demand during Moses's Sinai absence is the founding instance of Israel's idolatry. The specific catalyst is the perceived absence of the leader — 'we do not know what happened to him'. The Christological echo: in the absence of the risen Christ (physically ascended), the temptation is to manufacture visible substitutes for the invisible Lord. Idolatry is always a response to perceived divine absence.</p>",
    "41": "<p>'And they made a calf in those days, and offered a sacrifice to the idol and were rejoicing in the works of their hands' — the golden calf combines false worship, dead idols, and self-congratulation. The Christological contrast: true worship is directed to the risen Christ whom 'no one has ever seen' but who is present through the Spirit; true sacrifice is the 'living sacrifice' of one's whole life (Rom 12:1), not the manipulation of human craftsmanship. The 'works of their hands' (<em>tois ergois tōn cheirōn autōn</em>) will reappear in v. 48 as the critique of the temple itself.</p>",
    "42": "<p>'But God turned away and gave them over to worship the host of heaven, as it is written in the book of the prophets' — the divine 'giving over' (Amos 5:25-27 cited in vv. 42-43) is Paul's theological framework in Romans 1:24-28: God gives over those who exchange the truth of God for a lie. The Christological implication: the rejection of the true Deliverer consistently results in divine abandonment to lesser substitutes. The prophetic critique of Israel's idolatry that Stephen cites is simultaneously an implicit critique of the present court's rejection of Jesus.</p>",
    "43": "<p>The Amos citation — 'you took up the tent of Moloch and the star of your god Rephan' — identifies Israel's wilderness idolatry with the surrounding Canaanite and Babylonian cults. The Christological critique: idolatry is always syncretism — borrowing the world's worship objects to fill the void left by rejecting the living God. The tent of Moloch (a pagan portable shrine) is the perverse counterpart to the tabernacle of God's design (v. 44). Israel simultaneously had the true portable sanctuary and imported the false one.</p>",
    "44": "<p>'Our fathers had the tent of witness in the wilderness, just as he who spoke to Moses directed him to make it, according to the pattern that he had seen' — the tabernacle's design came from the heavenly pattern (<em>typon</em>, 'type') that Moses saw on Sinai (Exod 25:9, 40). The Christological use of 'type' in Hebrews (Heb 8:5; 9:24): the tabernacle was a copy and shadow of the heavenly sanctuary that Christ entered as high priest. The earthly tent pointed beyond itself to the true dwelling of God that Christ opened.</p>",
    "45": "<p>'Our fathers in turn brought it in with Joshua when they dispossessed the nations that God drove out before our fathers. So it was until the days of David' — the tabernacle's journey from Sinai to Canaan with Joshua (whose name is the same as Jesus — both are <em>Iēsous/Yehoshua</em>) to David prefigures the Christological completion of the Exodus: Joshua/Jesus bringing the people of God into their inheritance. The typological connection between Joshua and Jesus (same name, same role of bringing God's people into rest) is the basis of Hebrews 4:8's argument.</p>",
    "46": "<p>'David found favor in the sight of God and asked to find a dwelling place for the God of Jacob' — David's desire to build a house for God (2 Sam 7:1-3) was answered with the Davidic covenant promise that God would build David a house (a dynastic line). The Christological fulfillment: what David wanted to do for God (build a permanent dwelling) is what God accomplished in Christ — the Word became flesh and 'tabernacled among us' (John 1:14, <em>eskenōsen en hēmin</em>). God solved the dwelling-place question by becoming the dwelling himself.</p>",
    "47": "<p>'But it was Solomon who built a house for him' — Solomon built the temple that David wanted to build. The temple is the institutional culmination of the tabernacle trajectory. Stephen's citation without celebration: he is setting up the critique that follows. The Christological reading of the temple-building: the building is penultimate, never ultimate. It housed the divine presence provisionally; Christ is the permanent dwelling of the divine fullness (Col 2:9 — 'in him the whole fullness of deity dwells bodily').</p>",
    "48": "<p>A theme: 'Yet the Most High does not dwell in houses made by hands (<em>cheiropoiētois</em>)' — <em>cheiropoiētos</em> (made by human hands) is the LXX vocabulary for idols (Lev 26:1; Isa 2:18; 10:11; 16:12). By applying the idol-vocabulary to the temple, Stephen makes his most provocative claim: the temple, when treated as God's permanent residence, becomes functionally idolatrous — an attempt to confine the divine presence in human construction. The Christological resolution: Christ's resurrection body is the true temple (John 2:19-21 — 'destroy this temple, and in three days I will raise it up').</p>",
    "49": "<p>'Heaven is my throne, and the earth is my footstool. What kind of house will you build for me, says the Lord, or what is the place of my rest?' (Isa 66:1-2) — the Isaiah citation makes the theological point with divine authority. A God whose throne is heaven and whose footstool is earth cannot be contained in any human building. The Christological implication: what Solomon's temple could not provide — God's permanent dwelling with humanity — Christ accomplishes: 'Behold, the dwelling place of God is with man' (Rev 21:3). Not the temple but the incarnate, crucified, risen, glorified Son is where God truly dwells.</p>",
    "50": "<p>'Did not my hand make all these things?' — the Creator's rhetorical question (Isa 66:2) exposes the category error of the temple ideology: the hands that made the universe cannot be housed in what human hands make. The Christological reversal: instead of human hands building a house for God, God's hands (through the Spirit, Luke 1:35 — the incarnation as divine act) built the true house — a human body. The direction of construction is reversed: not human hands housing God, but divine action creating the embodied Son.</p>",
    "51": "<p>'You stiff-necked people, uncircumcised in heart and ears, you always resist the Holy Spirit. As your fathers did, so do you.' — the speech's turn: from history to indictment. Stephen's accusation has two parts: (1) they are 'uncircumcised in heart' — the Christological critique of mere external religion (Jer 4:4; Deut 10:16; Rom 2:29 — 'a Jew is one inwardly, and circumcision is a matter of the heart, by the Spirit'). (2) They 'always resist the Holy Spirit' — the pattern the whole speech traced is now named. Every generation's rejection of God's deliverers is resistance to the Spirit who sent them.</p>",
    "52": "<p>A direct revelation: 'Which of the prophets did your fathers not persecute? And they killed those who announced beforehand the coming of the Righteous One (<em>tou dikaiou</em>), and you have now become his betrayers and murderers.' The 'Righteous One' (<em>ho dikaios</em>) is the most archaic Christological title in Acts — also used in 3:14 and 22:14. It identifies Jesus with the persecuted righteous one of the Psalms (Ps 34:19; 37:12), the suffering servant of Isa 53:11, and the righteous sufferer of Wisdom of Solomon 2:12-20. The court that is trying Stephen is the court that murdered the Righteous One.</p>",
    "53": "<p>'You who received the law as delivered by angels and did not keep it' — the closing indictment connects law-reception with law-violation. The irony is judicial: the court that is prosecuting Stephen for blasphemy against the law has itself broken the law's deepest commandment (loving God with heart and soul and mind), rejected the prophets the law commended, and murdered the one all the law pointed toward. The Christological indictment: the law given through angels, if rightly kept, leads to the Christ it anticipates. To reject Christ is to reject the law's own telos.</p>",
    "54": "<p>'Now when they heard these things they were enraged, and they ground their teeth at him' (<em>dieprionto tais kardiais autōn</em>, they were cut to their hearts in rage) — the contrast with Pentecost: there, the crowd 'were cut to the heart' (<em>katenygesan tēn kardian</em>) in conviction and repentance (2:37). Here, the Sanhedrin is cut to the heart in murderous rage. The same Christological proclamation produces opposite responses depending on the hearer's posture: those who are open receive conviction unto repentance; those who are closed receive condemnation unto hardening.</p>",
    "55": "<p>'But he, full of the Holy Spirit, gazed into heaven and saw the glory of God, and Jesus standing at the right hand of God' — the Spirit-filling enables the vision of Christological reality that sustains martyrdom. Stephen sees what Paul will confess as the content of faith: the glory of God in the face of Jesus Christ (2 Cor 4:6). The glory (<em>doxan tou theou</em>) that Moses saw at Sinai, that filled Solomon's temple, is now concentrated in the face of the risen Jesus who stands to receive his martyr.</p>",
    "57": "<p>'But they cried out with a loud voice and stopped their ears and rushed together at him' — the deliberate, violent refusal to hear is the bodily enactment of the 'uncircumcised ears' Stephen accused them of (v. 51). They physically stop their ears to prevent the possibility that the Christological witness might penetrate. The Christological echo: 'He who has ears to hear, let him hear' (Luke 8:8) is met by those who choose not to have ears. Hearing requires willingness; rejection is always an active, not a passive, choice.</p>",
    "58": "<p>'They cast him out of the city and stoned him. And the witnesses laid down their garments at the feet of a young man named Saul' — the execution pattern mirrors the execution of Jesus: led out of the city (Jesus crucified outside Jerusalem, Heb 13:12), killed by the establishment's authorization. Saul's first appearance is as the guardian of the executioners' garments — a passive consent that Acts will develop into active persecution (8:3). The Christological community produces its first martyr; its future chief apostle watches his death.</p>",
    "59": "<p>'And as they were stoning Stephen, he called out, 'Lord Jesus, receive my spirit'' — the prayer to 'Lord Jesus' to receive his spirit is the equivalent of Jesus's own prayer to the Father at death ('Father, into your hands I commit my spirit', Luke 23:46). Where Jesus prays to the Father, Stephen prays to Jesus — a Christological equation that places Jesus in the position of the Father as the receiver of the departing spirit. The martyrdom prayer is an implicit confession of Christ's divinity: only God receives the returning spirit.</p>",
    "60": "<p>'And he knelt down and cried out with a loud voice, 'Lord, do not hold this sin against them.' And when he had said this, he fell asleep.' The prayer for his killers' forgiveness (echoing Jesus's own prayer, Luke 23:34 — 'Father, forgive them, for they know not what they do') is the Christological mark of Stephen's martyrdom. The one who dies in Christ's pattern prays in Christ's pattern. The 'falling asleep' (<em>ekoimēthē</em>) vocabulary — the earliest Christian euphemism for death — reflects the resurrection faith that death for the believer is now sleep awaiting awakening (1 Cor 15:20; 1 Thess 4:13-14). Stephen falls asleep trusting in the one who is the resurrection and the life.</p>"
  }
}

def main():
    existing = load_comm('mkt-christ', 'acts')
    merge_comm(existing, CHRIST)
    merge_comm(existing, FILL_CH7)
    save_comm('mkt-christ', 'acts', existing)
    total = sum(len(v) for v in existing.values())
    print(f'Acts mkt-christ: {len(existing)} chapters, {total} verses.')

if __name__ == '__main__':
    main()
